function ThemeSwitcher() {
  const [dark, setDark] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem("theme");
    const os = window.matchMedia("(prefers-color-scheme: dark)").matches;
    const initial = saved ? saved === "dark" : os;
    setDark(initial);
    document.documentElement.setAttribute("data-theme", initial ? "dark" : "light");
  }, []);

  const toggle = () => {
    const next = !dark;
    setDark(next);
    document.documentElement.setAttribute("data-theme", next ? "dark" : "light");
    localStorage.setItem("theme", next ? "dark" : "light");
  };

  return (
    <button
      onClick={toggle}
      aria-label={dark ? "Switch to light mode" : "Switch to dark mode"}
      className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium
                 transition-all duration-300 border"
      style={{
        borderColor: "var(--border-col)",
        color: "var(--muted)",
        background: "var(--surface-raised)",
      }}
    >
      {dark ? <IconSun /> : <IconMoon />}
      <span className="hidden sm:inline">{dark ? "Light" : "Dark"}</span>
    </button>
  );
}

/* ══════════════════════════════════════════════════════
   THREE.JS — FLUID METABALL PAINT SHADER
   Smooth-minimum SDF blobs drifting from top, fusing
   into each other like thick paint being poured.
══════════════════════════════════════════════════════ */
const VERT_SHADER = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}`;

const FRAG_SHADER = `
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform vec2  uRes;
uniform int   uDark; // 1 = dark mode, 0 = light

vec3 palette(int i) {
  if (i == 0) return vec3(0.91, 0.0,  0.18);  // red
  if (i == 1) return vec3(1.0,  0.48, 0.0);   // amber
  if (i == 2) return vec3(0.0,  0.82, 1.0);   // cyan
  if (i == 3) return vec3(0.69, 0.23, 0.93);  // violet
  if (i == 4) return vec3(0.0,  0.89, 0.46);  // green
  if (i == 5) return vec3(1.0,  0.84, 0.0);   // yellow
  return             vec3(1.0,  0.42, 0.76);  // pink
}

vec2 blobPos(int i, float t) {
  float fi   = float(i);
  float speed = 0.07 + fi * 0.011;
  float x = mod(fi * 0.154 + 0.06 * sin(t * 0.35 + fi * 1.8), 0.9) + 0.05;
  float y = 1.25 + fi * 0.21;
  y = mod(y - t * speed, 1.55) - 0.15;
  x += 0.035 * sin(t * 0.55 + fi * 2.3);
  return vec2(x, y);
}

void main() {
  vec2 uv   = vUv;
  float ar  = uRes.x / uRes.y;

  float field = 0.0;
  vec3  cAcc  = vec3(0.0);
  float wAcc  = 0.0;

  for (int i = 0; i < 8; i++) {
    vec2  p    = blobPos(i, uTime);
    float r    = 0.075 + float(i) * 0.009;
    float dx   = (uv.x - p.x) * ar;
    float dy   = (uv.y - p.y);
    float dist = sqrt(dx*dx + dy*dy);
    float contrib = (r * r) / (dist * dist + 0.0001);
    field += contrib;
    float w = contrib * contrib;
    cAcc  += palette(i) * w;
    wAcc  += w;
  }

  float threshold = 1.0;
  float alpha = smoothstep(threshold - 0.1, threshold + 0.12, field);

  vec3 blobCol = wAcc > 0.0 ? cAcc / wAcc : vec3(1.0);

  // Lighter inner highlight
  float edge = smoothstep(threshold, threshold + 0.3, field);
  blobCol = mix(blobCol, blobCol + 0.2, edge * 0.35);

  // In light mode, darken blobs slightly so they're not too washed out
  if (uDark == 0) {
    blobCol *= 0.82;
    alpha   *= 0.75;
  }

  // Fade paint out below ~60% of hero height (top = 1.0 in vUv)
  float yFade = smoothstep(0.0, 0.52, 1.0 - vUv.y);
  alpha *= yFade;

  gl_FragColor = vec4(blobCol, alpha * 0.9);
}`;

function PaintCanvas({ dark }) {
  const mountRef = useRef < HTMLDivElement > (null);
  const darkRef = useRef(dark);
  darkRef.current = dark;

  useEffect(() => {
    const el = mountRef.current;
    if (!el) return;
    const W = el.clientWidth, H = el.clientHeight;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 1.5));
    el.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);

    const uniforms = {
      uTime: { value: 0 },
      uRes: { value: new THREE.Vector2(W, H) },
      uDark: { value: darkRef.current ? 1 : 0 },
    };

    const mat = new THREE.ShaderMaterial({
      vertexShader: VERT_SHADER, fragmentShader: FRAG_SHADER,
      uniforms, transparent: true, depthWrite: false,
    });
    const geo = new THREE.PlaneGeometry(2, 2);
    scene.add(new THREE.Mesh(geo, mat));

    const clock = new THREE.Clock();
    let frame;
    const tick = () => {
      frame = requestAnimationFrame(tick);
      uniforms.uTime.value = clock.getElapsedTime();
      uniforms.uDark.value = darkRef.current ? 1 : 0;
      renderer.render(scene, camera);
    };
    tick();

    const onResize = () => {
      const nW = el.clientWidth, nH = el.clientHeight;
      renderer.setSize(nW, nH);
      uniforms.uRes.value.set(nW, nH);
    };
    window.addEventListener("resize", onResize);

    return () => {
      cancelAnimationFrame(frame);
      window.removeEventListener("resize", onResize);
      mat.dispose(); geo.dispose(); renderer.dispose();
      if (el.contains(renderer.domElement)) el.removeChild(renderer.domElement);
    };
  }, []);

  return <div ref={mountRef} className="absolute inset-0 z-0 pointer-events-none" />;
}

/* ══════════════════════════════════════════════════════
   MAGNETIC TILT CARD
══════════════════════════════════════════════════════ */
function MagCard({ children, className = "" }) {
  const ref = useRef < HTMLDivElement > (null);
  const onMove = (e) => {
    const el = ref.current; if (!el) return;
    const r = el.getBoundingClientRect();
    const x = ((e.clientX - r.left) / r.width - 0.5) * 14;
    const y = ((e.clientY - r.top) / r.height - 0.5) * 14;
    el.style.transform = `perspective(700px) rotateY(${x}deg) rotateX(${-y}deg) translateZ(10px)`;
  };
  const onLeave = () => {
    if (ref.current) ref.current.style.transform = "";
  };
  return (
    <div ref={ref} className={className}
      onMouseMove={onMove} onMouseLeave={onLeave}
      style={{ transition: "transform 0.18s ease", willChange: "transform" }}>
      {children}
    </div>
  );
}

/* ══════════════════════════════════════════════════════
   SCROLL REVEAL HOOK
══════════════════════════════════════════════════════ */
function useReveal() {
  const ref = useRef < HTMLElement > (null);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    el.classList.add("reveal");
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) { el.classList.add("visible"); obs.disconnect(); }
    }, { threshold: 0.12 });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return ref;
}

